#include<bits/stdc++.h>
using namespace std;
int main() {
	unsigned long long a=0,b=0,n=0;
	string num,num2,num3,uu;
    cin>>num;
	for(int i=0;i<num.size();i++){
		if(num[i]>='0'&&num[i]<='9'){
			uu=num[i];
			num2.append(uu);
		}else{
			for(int j=i;j<num.size();j++){
				if(num[j]>='0'&&num[j]<='9'){
					uu=num[j];
					
					num3.append(uu);
				}
				
			}break;
		}
	}for(int i=0;i<num2.size();i++){
		a=a*10+(num2[i]-'0');
	}
	for(int i=0;i<num3.size();i++){
		
		b=b*10+(num3[i]-'0');
	}
	for (; a > 0;) {
				n = n * 10 + a % 10;
				a /= 10;
	}cout<<n;
	if(num.find(".")!=string::npos){
		if(n<1000){
			cout<<".0";return 0;
		}n=0;
		for (; b > 0;) {
								n = n * 10 + b % 10;
								b /= 10;
			}if(n!=0){cout<<".";cout<<n;}
	}if(num.find("/")!=string::npos){
			cout<<"/";n=0;
			for (; b > 0;) {
									n = n * 10 + b % 10;
									b /= 10;
				}cout<<n;
	}if(num.find("%")!=string::npos){
		cout<<"%";
	}
}
